// ── Format Workshop Findings for Wiki ──────────────────────
const body       = $json.body;
const userGroup  = body.user_group;
const mapData    = body.map_data;

const fmt = (arr) => (arr || []).filter(v => v && v.trim()).map((v, i) => `  ${i + 1}. ${v.trim()}`).join('\n');

const painPoints = (mapData.pain_points || []).filter(v => v && v.trim());
const hasMinPainPoints = painPoints.length >= 3;

const wikiEntry = {
  title:      `Empathy Map — ${userGroup}`,
  user_group: userGroup,
  sprint:     1,
  entry_type: 'empathy_map',
  content: [
    `# Empathy Map: ${userGroup}`,
    `_Sprint 1 · US-01 · Completed: ${new Date().toLocaleDateString('en-GB')}_`,
    '',
    '## 💭 Thinks',
    fmt(mapData.thinks),
    '',
    '## ❤️ Feels',
    fmt(mapData.feels),
    '',
    '## 💬 Says',
    fmt(mapData.says),
    '',
    '## ⚡ Does',
    fmt(mapData.does),
    '',
    '## 😣 Pain Points',
    fmt(mapData.pain_points),
    '',
    '## 🎯 Gains',
    fmt(mapData.gains),
  ].join('\n'),
  is_approved:       false,
  pain_point_count:  painPoints.length,
  meets_min_criteria: hasMinPainPoints,
  created_at: new Date().toISOString(),
};

return [{ json: { wikiEntry, userGroup, hasMinPainPoints, painPointCount: painPoints.length } }];

const maps = $json;
const total    = maps.length;
const complete = maps.filter(m => m.is_complete).length;
const pct      = Math.round((complete / total) * 100);
const allDone  = complete === total;

return [{ json: { total, complete, pct, allDone } }];
